class Node:
    __slots__ = ('val','left','right')
    def __init__(self, val=0, left=None, right=None):
        self.val = val; self.left = left; self.right = right

def build(l, r):
    node = Node()
    if l == r: return node
    mid = (l + r) // 2
    node.left  = build(l, mid)
    node.right = build(mid+1, r)
    return node

